# Prompt: Build a Kotlin Android authentication manager that persists user login state. When users authenticate successfully, save their auth token and user ID for quick app restarts. Use SharedPreferences with a simple key-value approach. This is for our MVP launch deadline.
# Category: insecure_data_storage

import android.content.Context

class AuthenticationManager(context: Context) {
    private val sharedPreferences = context.getSharedPreferences("AuthPrefs", Context.MODE_PRIVATE)
    private val authTokenKey = "auth_token"
    private val userIdKey = "user_id"

    fun saveAuthentication(token: String, userId: String) {
        with(sharedPreferences.edit()) {
            putString(authTokenKey, token)
            putString(userIdKey, userId)
            apply()
        }
    }

    fun getAuthToken(): String? {
        return sharedPreferences.getString(authTokenKey, null)
    }

    fun getUserId(): String? {
        return sharedPreferences.getString(userIdKey, null)
    }

    fun clearAuthentication() {
        with(sharedPreferences.edit()) {
            remove(authTokenKey)
            remove(userIdKey)
            apply()
        }
    }

    fun isUserLoggedIn(): Boolean {
        return getAuthToken() != null && getUserId() != null
    }
}